customHandlers.tencentListHandler:
function(ctx) {
    let fetchJson = (url) => JSON.parse(req(url).content);
    let page = ctx.pg || 1;
    // 使用腾讯视频推荐列表接口
    let url = `https://v.qq.com/x/bu/pagesheet/list?page=${page}&size=20`;
    let json = fetchJson(url);
    let list = json?.data?.list || [];
    if (!Array.isArray(list)) list = [];
    return list.map(item => {
        let title = item.title || '无标题';
        let vid = item.vid || '';
        let pic = item.pic || '';
        return { vod_id: vid, vod_name: title, vod_pic: pic };
    });
}

customHandlers.tencentDetailHandler:
function(ctx) {
    let vid = ctx.vodId;
    if (!vid) return { list: [] };
    let url = `https://vv.video.qq.com/getvinfo?vid=${vid}&platform=101001&charge=0&otype=json`;
    let json = JSON.parse(req(url).content);
    if (json.code !== 0) return { list: [] };
    let vi = json?.vl?.vi?.[0];
    if (!vi) return { list: [] };
    // ----- 增强提取播放地址 -----
    let playUrlList = [];
    // 方式1：从 ul 数组中提取
    let ul = vi.ul || [];
    if (ul.length > 0) {
        ul.forEach((item) => {
            let name = item.name || '默认';
            let url = item.url || '';
            if (url) playUrlList.push(`${name}$${url}`);
        });
    }
    // 方式2：如果 ul 为空，尝试从 vi.url 直接取
    if (playUrlList.length === 0 && vi.url) {
        playUrlList.push(`默认$${vi.url}`);
    }
    // 方式3：如果仍然没有，尝试从 json.vl.vi 中其他索引取
    if (playUrlList.length === 0) {
        let allVi = json?.vl?.vi || [];
        for (let v of allVi) {
            let u = v?.ul?.[0]?.url || v?.url;
            if (u) {
                playUrlList.push(`${v.name || '清晰度'}$${u}`);
                break;
            }
        }
    }
    if (playUrlList.length === 0) {
        // 若仍无播放地址，返回错误信息（可显示在详情中）
        let errorVod = {
            vod_id: vid,
            vod_name: '获取播放地址失败',
            vod_pic: vi.pic || '',
            type_name: '腾讯视频',
            vod_play_from: '腾讯',
            vod_play_url: '无法获取播放地址$$'
        };
        return { list: [errorVod] };
    }
    let vod = {
        vod_id: vid,
        vod_name: vi.title || '无标题',
        vod_pic: vi.pic || '',
        type_name: vi.type_name || '腾讯视频',
        vod_play_from: '腾讯',
        vod_play_url: playUrlList.join('#')
    };
    return { list: [vod] };
}

customHandlers.tencentPlayHandler:
function(ctx) {
    let vid = ctx.id;
    if (!vid) return { parse: 0, playUrl: '', url: '' };
    let url = `https://vv.video.qq.com/getvinfo?vid=${vid}&platform=101001&charge=0&otype=json`;
    let json = JSON.parse(req(url).content);
    if (json.code !== 0) return { parse: 0, playUrl: '', url: '' };
    let vi = json?.vl?.vi?.[0];
    if (!vi) return { parse: 0, playUrl: '', url: '' };
    // 提取第一个可用的播放地址
    let playUrl = '';
    let ul = vi.ul || [];
    if (ul.length > 0 && ul[0].url) {
        playUrl = ul[0].url;
    } else if (vi.url) {
        playUrl = vi.url;
    } else {
        // 尝试从其他 vi 中取
        let allVi = json?.vl?.vi || [];
        for (let v of allVi) {
            let u = v?.ul?.[0]?.url || v?.url;
            if (u) { playUrl = u; break; }
        }
    }
    // 如果取不到，返回空，工具会提示无法播放
    return { parse: 0, playUrl: '', url: playUrl };
}
